// Service Worker for Vibe Message Push Notifications
// Auto-generated by vibe-message SDK

const swUrl = new URL(self.location.href);
const baseUrl = swUrl.searchParams.get("baseUrl") || "http://localhost:3000/api";

self.addEventListener("push", (event) => {
  console.log("[Service Worker] Push notification received:", event);

  let data = {};
  try {
    data = event.data ? event.data.json() : {};
  } catch (e) {
    console.error("[SW] Failed to parse push data", e);
  }

  const logId = data.notificationLogId;

  const reportStatus = (status, errorMsg) => {
    if (!logId) return Promise.resolve();
    return fetch(`${baseUrl}/sdk/track`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        logId: logId,
        status: status,
        errorMessage: errorMsg
      }),
    }).catch((err) => {
      console.error("[SW] Failed to report tracking status:", err);
    });
  };

  const promise = Promise.resolve().then(() => {
    // Parse stringified JSON custom data if needed
    let customData = data.data || {};
    if (typeof customData === "string") {
      try {
        customData = JSON.parse(customData);
      } catch (e) {
        // Fallback if not stringified JSON
      }
    }

    // Handle silent notifications (no UI, just data sync)
    if (data.silent) {
      console.log("[Service Worker] Silent push notification received:", data);
      return self.clients
        .matchAll({ includeUncontrolled: true, type: "window" })
        .then((clients) => {
          // Send silent message to all clients
          clients.forEach((client) => {
            client.postMessage({
              type: "SILENT_MESSAGE",
              data: customData,
            });
          });
          return reportStatus("DELIVERED");
        });
    }

    // Check if any client window is focused (app is visible)
    return self.clients
      .matchAll({ includeUncontrolled: true, type: "window" })
      .then((clients) => {
        const focusedClient = clients.find((client) => client.visibilityState === "visible" || client.focused);

        if (focusedClient) {
          // App is visible - send message to foreground
          focusedClient.postMessage({
            type: "FOREGROUND_MESSAGE",
            payload: {
              title: data.title || "Notification",
              body: data.body || "",
              icon: data.icon || "/demo-app/icon.png",
              data: customData,
            }
          });
          return reportStatus("DELIVERED");
        } else {
          // App is not visible - show push notification
          console.log(
            "[Service Worker] App is not visible, showing push notification"
          );
          const title = data.title || "Notification";
          const options = {
            body: data.body || "",
            icon: data.icon || "/demo-app/icon.png",
            image: data.image,
            badge: "/demo-app/badge.png",
            data: {
              click_action: data.click_action || "/demo-app/",
              ...(typeof customData === "object" && customData !== null ? customData : { data: customData }),
            },
            requireInteraction: false,
            tag: "vibe-message-notification",
          };

          return self.registration.showNotification(title, options)
            .then(() => reportStatus("DELIVERED"))
            .catch((err) => reportStatus("FAILED", "SW_SHOW_NOTIFICATION_ERROR: " + err.message));
        }
      });
  }).catch((err) => {
    return reportStatus("FAILED", "SW_PROCESS_ERROR: " + err.message);
  });

  event.waitUntil(promise);
});

self.addEventListener("notificationclick", (event) => {
  console.log("[Service Worker] Notification clicked:", event);

  event.notification.close();

  const urlToOpen = event.notification.data?.click_action || "/demo-app/";
  const absoluteUrl = new URL(urlToOpen, self.location.origin).href;

  event.waitUntil(
    self.clients
      .matchAll({ type: "window", includeUncontrolled: true })
      .then((clientList) => {
        // 1. Try to find a window with the exact URL
        for (const client of clientList) {
          if (client.url === absoluteUrl && "focus" in client) {
            // Send background message callback
            client.postMessage({
              type: "BACKGROUND_MESSAGE",
              payload: event.notification.data,
            });
            return client.focus();
          }
        }

        // 2. If no exact match, try to find any open window under the same origin/scope
        for (const client of clientList) {
          if ("focus" in client && "navigate" in client) {
            // Send background message callback
            client.postMessage({
              type: "BACKGROUND_MESSAGE",
              payload: event.notification.data,
            });
            client.navigate(absoluteUrl);
            return client.focus();
          }
        }

        // 3. If no window is open, open a new one
        if (self.clients.openWindow) {
          return self.clients.openWindow(absoluteUrl).then((client) => {
            if (client) {
              // Send background message to new window
              client.postMessage({
                type: "BACKGROUND_MESSAGE",
                payload: event.notification.data,
              });
            }
          });
        }
      })
  );
});

self.addEventListener("notificationclose", (event) => {
  console.log("[Service Worker] Notification closed:", event);
});

// Handle service worker activation
self.addEventListener("activate", (event) => {
  console.log("[Service Worker] Activated");
  event.waitUntil(self.clients.claim());
});

// Handle service worker installation
self.addEventListener("install", (event) => {
  console.log("[Service Worker] Installed");
  self.skipWaiting();
});
